// Replicate the helpers from app.css.test.ts and assert they pass against a
// synthetic CSS that contains EXACTLY the rules the task specifies (appended to
// the real file's tail). This confirms the new tests are not falsely failing.

import { readFileSync } from 'node:fs';

function stripComments(css) { return css.replace(/\/\*[\s\S]*?\*\//g, ''); }

function parseRules(css) {
  const rules = [];
  let i = 0;
  while (i < css.length) {
    const open = css.indexOf('{', i);
    if (open === -1) break;
    const selector = css.slice(i, open).trim();
    let depth = 1, j = open + 1;
    while (j < css.length && depth > 0) {
      if (css[j] === '{') depth++;
      else if (css[j] === '}') depth--;
      j++;
    }
    const declarations = css.slice(open + 1, j - 1);
    if (selector.length > 0) rules.push({ selector, declarations });
    i = j;
  }
  return rules;
}

// Real current app.css (no new rules yet) + the task's exact new rules.
const REAL = readFileSync('/home/blake/Documents/software/map-large-homework/.engin/work/1781984414963-develop/task-worktrees/t-03/src/app.css', 'utf8');

const NEW_RULES = `
/* ── Search wrapper ── */
.search-wrapper {
  position: relative;
  display: inline-flex;
  align-items: center;
  margin-left: auto;
}
.search-wrapper input[type='text'] {
  margin-left: 0;
  padding-right: 28px;
}
.search-wrapper .search-icon,
.search-wrapper .clear-btn {
  position: absolute;
  right: 6px;
  color: #9a9a9a;
}
.search-wrapper .search-icon {
  pointer-events: none;
}
.search-wrapper .clear-btn {
  background: none;
  border: none;
  cursor: pointer;
  padding: 2px;
  display: inline-flex;
  align-items: center;
  line-height: 1;
}
.clear-btn:hover {
  color: #e6e6e6;
}
.search-wrapper .clear-btn {
  display: none;
}
.search-wrapper input:not(:placeholder-shown) ~ .search-icon {
  display: none;
}
.search-wrapper input:not(:placeholder-shown) ~ .clear-btn {
  display: inline-flex;
}

/* ── Spinner ── */
@keyframes spin {
  to { transform: rotate(360deg); }
}
.spinning {
  animation: spin 1s linear infinite;
  display: inline-block;
}
.search-spinner {
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 16px;
  color: #9a9a9a;
